arguments.command:
FONT=$(fc-match 'JetBrainsMono Nerd Font' -f '%{file}'); fc-query "$FONT" -f 'family=%{family}
spacing=%{spacing}
charset=%{charset}
' > /tmp/jbnf-query; wc -c /tmp/jbnf-query; head -3 /tmp/jbnf-query

node <<'JS'
const g=require('/tmp/glyphnames.json'); console.log(Object.keys(g).length, Object.entries(g).slice(0,2));
let re=/(spinner|spin|loading|progress|circle|slice|rotate|rotation|timer|clock|dots|orbit|ellipsis|hourglass|sync|refresh|loader|motion)/i;
for(const [n,v] of Object.entries(g)) if(re.test(n)) console.log(n,JSON.stringify(v));
JS

