FONT=$(fc-match 'JetBrainsMono Nerd Font' -f '%{file}'); P=$(nix build --no-link --print-out-paths nixpkgs#python3Packages.fonttools); $P/bin/ttx -q -t cmap -t hmtx -t head -o /tmp/jbnf.ttx "$FONT"; node <<'JS'
const fs=require('fs');let x=fs.readFileSync('/tmp/jbnf.ttx','utf8');
let cps=[]; for(let cp of [...Array(8)].map((_,i)=>0xf0a9e+i).concat([...Array(6)].map((_,i)=>0xee06+i),[...Array(6)].map((_,i)=>0xf0ac3+i),[...Array(24)].map((_,i)=>0xf143f+i))){let hx=cp.toString(16);let m=x.match(new RegExp('<map code="0x'+hx+'" name="([^"]+)"'));let n=m?.[1];let hm=n&&x.match(new RegExp('<mtx name="'+n.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+'" width="([0-9]+)" lsb="(-?[0-9]+)"'));console.log('U+'+cp.toString(16).toUpperCase(),n,hm?.[1],hm?.[2])}
JS
head -20 /tmp/jbnf.ttx | tail -5

FONT=$(fc-match 'JetBrainsMono Nerd Font' -f '%{file}'); P=$(nix build --no-link --print-out-paths nixpkgs#python3Packages.fonttools); $P/bin/ttx -q -t glyf -o /tmp/jbnf-glyf.ttx "$FONT"; node <<'JS'
const x=require('fs').readFileSync('/tmp/jbnf-glyf.ttx','utf8');for(let pref of ['md-circle_slice_','md-hexagon_slice_','md-clock_time_','extra-progress_spinner_']){console.log(pref);let re=new RegExp('<TTGlyph name="('+pref+'[^"]+)" xMin="([^"]+)" yMin="([^"]+)" xMax="([^"]+)" yMax="([^"]+)"','g'),m;while(m=re.exec(x))console.log(m.slice(1).join(' '))}
JS
